CREATE TABLE IF NOT EXISTS activity_logs (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, user_id VARCHAR(128) NOT NULL, event_type VARCHAR(64) NOT NULL, ip_address VARCHAR(45), device VARCHAR(160), status VARCHAR(32) NOT NULL, risk_level VARCHAR(20) NOT NULL CHECK (risk_level IN ('low','medium','high','critical')), risk_score DOUBLE PRECISION NOT NULL CHECK (risk_score BETWEEN 0 AND 100), details JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
